import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { Link, useLocation } from "react-router-dom";
import BusCard from "../components/BusCard";
import { Bus } from "../types";

const API_BASE = "http://localhost:5000/api";

type TimeFilter = "all" | "morning" | "evening";

const BusList: React.FC = () => {
  const [buses, setBuses] = useState<Bus[]>([]);
  const [loading, setLoading] = useState(true);
  const [timeFilter, setTimeFilter] = useState<TimeFilter>("all");
  const location = useLocation();

  const searchInfo = useMemo(() => {
    const params = new URLSearchParams(location.search);
    return {
      departureCity: params.get("departureCity") || "",
      arrivalCity: params.get("arrivalCity") || "",
      date: params.get("date") || ""
    };
  }, [location.search]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        setLoading(true);
        const params = new URLSearchParams();
        if (searchInfo.departureCity) params.append("departureCity", searchInfo.departureCity);
        if (searchInfo.arrivalCity) params.append("arrivalCity", searchInfo.arrivalCity);

        const response = await axios.get<Bus[]>(`${API_BASE}/buses?${params.toString()}`);
        setBuses(response.data);
      } catch (error) {
        console.error("Failed to fetch buses", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBuses();
  }, [searchInfo.departureCity, searchInfo.arrivalCity]);

  const filteredBuses = useMemo(() => {
    if (timeFilter === "all") return buses;

    return buses.filter((bus) => {
      const hour = new Date(bus.departureTime).getHours();
      if (timeFilter === "morning") return hour >= 5 && hour < 12;
      if (timeFilter === "evening") return hour >= 17 && hour < 24;
      return true;
    });
  }, [buses, timeFilter]);

  const quickStats = useMemo(() => {
    const morning = buses.filter((bus) => {
      const hour = new Date(bus.departureTime).getHours();
      return hour >= 5 && hour < 12;
    }).length;

    const evening = buses.filter((bus) => {
      const hour = new Date(bus.departureTime).getHours();
      return hour >= 17 && hour < 24;
    }).length;

    return {
      total: buses.length,
      morning,
      evening
    };
  }, [buses]);

  const filterBtnClass = (value: TimeFilter) =>
    `rounded-lg px-4 py-2 text-sm font-semibold transition ${
      timeFilter === value ? "bg-blue-600 text-white" : "border border-slate-300 text-slate-700 hover:bg-slate-100"
    }`;

  return (
    <section>
      <div className="mb-6 flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Available Buses</h2>
          <p className="text-sm text-slate-600">
            {searchInfo.departureCity || "All cities"} {" -> "} {searchInfo.arrivalCity || "All cities"}
            {searchInfo.date ? ` | ${searchInfo.date}` : ""}
          </p>
        </div>
        <Link to="/" className="rounded-lg border border-slate-300 px-4 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100">
          Modify Search
        </Link>
      </div>

      <div className="mb-5 grid gap-3 sm:grid-cols-3">
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Total Buses</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.total}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Morning (5AM-12PM)</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.morning}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Evening (5PM-12AM)</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.evening}</p>
        </div>
      </div>

      <div className="mb-5 flex flex-wrap gap-2">
        <button type="button" className={filterBtnClass("all")} onClick={() => setTimeFilter("all")}>
          All
        </button>
        <button type="button" className={filterBtnClass("morning")} onClick={() => setTimeFilter("morning")}>
          Morning
        </button>
        <button type="button" className={filterBtnClass("evening")} onClick={() => setTimeFilter("evening")}>
          Evening
        </button>
      </div>

      {loading ? <p className="text-slate-600">Loading buses...</p> : null}
      {!loading && filteredBuses.length === 0 ? (
        <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">
          No buses found for this route and time filter.
        </div>
      ) : null}

      <div className="grid gap-4 md:grid-cols-2">
        {filteredBuses.map((bus) => (
          <BusCard key={bus.id} bus={bus} />
        ))}
      </div>
    </section>
  );
};

export default BusList;
